// Combine all kanji
export const ALL_KANJI = [...N5_KANJI, ...N4_KANJI, ...N3_KANJI, ...N2_KANJI, ...N1_KANJI];

export const JLPT_LEVELS = ["N5", "N4", "N3", "N2", "N1"];
export const GRADES = ["1", "2", "3", "4", "5", "6", "Secondary"];

export function getKanjiByLevel(level) {
  return ALL_KANJI.filter(k => k.jlpt_level === level);
}

export function getKanjiByGrade(grade) {
  return ALL_KANJI.filter(k => k.grade === grade);
}

// Generate SVG stroke order URL from KanjiVG
export function getStrokeOrderUrl(character) {
  const codePoint = character.codePointAt(0).toString(16).padStart(5, '0');
  return `https://raw.githubusercontent.com/KanjiVG/kanjivg/master/kanji/${codePoint}.svg`;
}